#include<bits/stdc++.h>
using namespace std;
long long n,m;
long long f[200010][21],d[200010];
vector<long long> mp[200010];
void dfs(long long x,long long fa=0)
{
    d[x]=d[fa]+1;
    f[x][0]=fa;
    for(long long i=1;i<=20;i++)
    {
        f[x][i]=f[f[x][i-1]][i-1];
    }
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            dfs(i,x);
        }
    }
}
long long lg[200010];
long long lca(long long x,long long y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=f[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(long long i=20;i>=0;i--)
    {
        if(f[x][i]!=f[y][i])
        {
            x=f[x][i];
            y=f[y][i];
        }
    }
    return f[x][0];
}
long long cnt[100010];
void update(long long x,long long y)
{
    cnt[x]++;
    cnt[y]++;
    long long l=lca(x,y);
    cnt[l]-=2;
}
long long ans;
void getans(long long x,long long fa=0)
{
    for(long long i:mp[x])
    {
        if(i!=fa)
        {
            getans(i,x);
            cnt[x]+=cnt[i];
        }
    }
}
int main()
{
    for(long long i=2;i<=200000;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<n;i++)
    {
        long long a,b;
        scanf("%lld%lld",&a,&b);
        mp[a].push_back(b);
        mp[b].push_back(a);
    }
    dfs(1);
    for(long long i=1;i<=m;i++)
    {
        long long a,b;
        scanf("%lld%lld",&a,&b);
        update(a,b);
    }
    getans(1);
    for(long long i=2;i<=n;i++)
    {
        if(cnt[i]==1)
        {
            ans++;
        }
        if(cnt[i]==0)
        {
            ans+=m;
        }
    }
    printf("%lld",ans);
    return 0;
}
